# apply projections for DAP4 (similar to DAP2)
for var in self.projection:
    target = self.dataset
    while var:
        token, index = var.pop(0)
        # For DAP4, tokens may start with '/' which needs to be stripped
        if token.startswith('/'):
            token = token[1:]
        target = target[token]
        if isinstance(target, pydap.model.BaseType):
            # Transform constraint slice to be appropriate for constrained data shape
            # The constraint [start:step:stop] on original data returns shape with
            # (stop - start + 1) // step elements, so we should allow accessing all of them
            transformed_slices = []
            for constraint_slice, dim_size in zip(index, target.shape):
                if isinstance(constraint_slice, slice):
                    # For a constraint slice that selects a range, the proxy should
                    # allow accessing the full constrained dimension
                    transformed_slices.append(slice(0, dim_size, 1))
                else:
                    transformed_slices.append(constraint_slice)
            target.data.slice = tuple(transformed_slices)
        elif isinstance(target, pydap.model.GridType):
            # Transform constraint slice for grid arrays
            transformed_slices = []
            for constraint_slice, dim_size in zip(index, target.array.shape):
                if isinstance(constraint_slice, slice):
                    transformed_slices.append(slice(0, dim_size, 1))
                else:
                    transformed_slices.append(constraint_slice)
            index = tuple(transformed_slices)
            target.array.data.slice = index
            for s, child in zip(index, target.maps):
                target[child].data.slice = (s,)
        elif isinstance(target, pydap.model.SequenceType):
            # For sequences, transform slice similarly
            if index and isinstance(index[0], slice):
                transformed_slices = []
                for constraint_slice, dim_size in zip(index, target.shape or [None]*len(index)):
                    if isinstance(constraint_slice, slice) and dim_size is not None:
                        transformed_slices.append(slice(0, dim_size, 1))
                    else:
                        transformed_slices.append(constraint_slice)
                target.data.slice = tuple(transformed_slices)
            else:
                target.data.slice = index

